#!/usr/bin/env python3
# chronicle — the garden's life story, replayed from the log. Reads every event
# on stdin and renders the growth milestones (birth, seeds taking root, new
# commands & ways of seeing, rollbacks, self-authored binaries) as a single
# chronological timeline, with a few vital signs up top. Bare semantic HTML +
# the kernel class vocabulary (card/muted/tag/row/num); the kernel themes it.
import sys, json
from html import escape

events = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        events.append(json.loads(line))
    except Exception:
        continue

def when(e):
    return (e.get("occurred_at", "") or "")[:19].replace("T", " ")

def day(e):
    return (e.get("occurred_at", "") or "")[:10]

# vital signs
total = len(events)
commands, projectors, seeds, compiles, restores = set(), set(), set(), 0, 0
for e in events:
    n = e.get("name", "")
    p = e.get("payload", {}) or {}
    nm = p.get("name", "")
    if n == "command.declared" and nm:
        commands.add(nm)
    elif n == "projector.declared" and nm:
        projectors.add(nm)
    elif n == "seed.planted" and p.get("seed"):
        seeds.add(p.get("seed"))
    elif n == "script.compiled":
        compiles += 1
    elif n == "restore.requested":
        restores += 1

born = next((when(e) for e in events if e.get("name") == "kernel.initialized"), "")
latest = when(events[-1]) if events else ""

# a milestone is a moment in the garden's becoming — not its daily traffic.
# (chat.message, wall.posted & friends are life lived, not life's shape; they
# belong to their own boards, the history list, and the raw /events log.)
def milestone(e):
    n = e.get("name", "")
    p = e.get("payload", {}) or {}
    nm = escape(p.get("name", "") or "")
    if n == "kernel.initialized":
        return ("born", "the kernel woke — a baby that knows only how to grow")
    if n == "seed.planted":
        sn = escape(p.get("seed", "") or "")
        c = len(p.get("commands") or [])
        pr = len(p.get("projectors") or [])
        parts = []
        if c:
            parts.append("%d command%s" % (c, "" if c == 1 else "s"))
        if pr:
            parts.append("%d view%s" % (pr, "" if pr == 1 else "s"))
        extra = " <span class='muted'>(%s)</span>" % escape(", ".join(parts)) if parts else ""
        return ("seed", "planted the <strong>%s</strong> seed%s" % (sn, extra))
    if n == "command.declared":
        d = escape((p.get("description", "") or "").strip().split(".")[0][:90])
        tail = " <span class='muted'>— %s</span>" % d if d else ""
        return ("learned", "learned to <strong>%s</strong>%s" % (nm, tail))
    if n == "projector.declared":
        return ("sees", "gained a way of seeing: <strong>%s</strong>" % nm)
    if n == "restore.requested":
        seq = p.get("seq")
        at = (" to seq %s" % escape(str(seq))) if seq is not None else ""
        return ("rollback", "rolled <strong>%s</strong> back%s" % (nm, at))
    return None

print("<!DOCTYPE html>")
print("<html><head><meta charset='utf-8'><title>chronicle</title></head><body>")
print("<h1>chronicle</h1>")
if not events:
    print("<p class='muted'>An unwritten garden. Nothing has happened yet.</p>")
    print("</body></html>")
    sys.exit(0)

print("<p class='muted'>How this garden came to be — replayed from the log, "
      "oldest first. %d event%s since %s.</p>" % (total, "" if total == 1 else "s", escape(born or "the beginning")))

# vital signs row of cards
print("<div class='row'>")
for label, value in (("events", total), ("capabilities", len(commands)),
                     ("ways of seeing", len(projectors)), ("seeds rooted", len(seeds)),
                     ("self-compiled", compiles), ("rollbacks", restores)):
    print("<div class='card'><div class='num' style='font-size:1.6rem;font-weight:700'>%d</div>"
          "<div class='muted'>%s</div></div>" % (value, escape(label)))
print("</div>")

# the timeline, grouped by day
print("<h2>the timeline</h2>")
last_day = None
shown = 0
for e in events:
    m = milestone(e)
    if not m:
        continue
    tag, text = m
    d = day(e)
    if d != last_day:
        print("<p class='muted' style='margin-top:22px'><strong>%s</strong></p>" % escape(d or "—"))
        last_day = d
    seq = e.get("seq", "")
    print("<div class='msg'>"
          "<span class='tag accent'>%s</span> "
          "<span class='who'>seq %s · %s</span> "
          "<div>%s</div></div>" % (escape(tag), escape(str(seq)), escape(when(e)), text))
    shown += 1

if shown == 0:
    print("<p class='muted'>No milestones yet — grow a seed and the story begins.</p>")

print("<p class='muted' style='margin-top:28px'>Latest heartbeat of record: %s. "
      "Everything here is a pure replay of <code>events.jsonl</code> — run it twice, "
      "get the same story.</p>" % escape(latest))
print("</body></html>")

